import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"更新 Fabric","description":"更新 Fabric 的手把手的指南","frontmatter":{"title":"更新 Fabric","description":"更新 Fabric 的手把手的指南","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"zh_cn/1.21.10/players/updating-fabric.md","filePath":"versions/1.21.10/translated/zh_cn/players/updating-fabric.md","lastUpdated":1766682904000}`);var c={name:`zh_cn/1.21.10/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">更新 Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “更新 Fabric”">​</a></h1><p>这篇指南将引导您在 Minecraft 启动器中更新 Fabric。</p><p>对于第三方启动器，应该参见这些第三方启动器的文档。</p><p>更新 Fabric 和安装 Fabric 的过程非常相似，所以该指南的一部分与 <a href="./installing-fabric">安装 Fabric</a> 指南完全一致。</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">为什么应该更新 Fabric Loader？ <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “为什么应该更新 Fabric Loader？”">​</a></h2><p>新的模组可能需要新版本的 Fabric Loader 才能运行，所以保持更新很重要，从而确保能够使用最新的模组。</p><p>本指南仅适用于官方的 Minecraft Launcher。 对于第三方启动器，应该参考它们的文档。</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. 下载 Fabric 安装器 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. 下载 Fabric 安装器”">​</a></h2><p>可以从 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 网站</a> 下载 Fabric 安装器。</p><p>如果使用 Windows，下载 <code>.exe</code> 版本 （<code>Download For Windows</code>），因为不需要你的系统已安装 Java， 而是使用官方启动器附带的 Java。</p><p>对于 macOS 和 Linux，您应该下载 <code>.jar</code> 版本。 有时，此步骤之前需要安装 Java。</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. 运行 Fabric 安装器 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. 运行 Fabric 安装器”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>在运行安装器之前，请先关闭 Minecraft 和 Minecraft Launcher。</p></div><details class="details custom-block"><summary>macOS 用户须知</summary><p>在 macOS 上，可能需要右键点击下载目录中的 <code>.jar</code>，然后点击 <code>Open</code> 来运行。</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Fabric 安装器中的 MacOS 上下文菜单" loading="lazy"></p><p>问到“Are you sure you want to open it?”时，再次点击 <code>Open</code>。</p></details><p>打开安装器后，应该会看到这样的屏幕：</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="高亮 &quot;Install&quot; 的 Fabric 安装器" loading="lazy"></p><p>要更新 Fabric，简单地确认游戏版本和加载器版本是正确的，然后点击 <code>安装</code> 。</p><div class="warning custom-block"><p class="custom-block-title">重要</p><p><strong>运行安装程序时，请确保没有选中“创建新的启动器配置”，否则将创建新的配置文件，而这种情况下我们不需要。</strong></p></div><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. 在 Minecraft 启动器中打开配置 <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. 在 Minecraft 启动器中打开配置”">​</a></h2><p>安装器完成后，可以打开 Minecraft 启动器并前往 <code>Installations（安装）</code> 选项。 您应当前往您的 Fabric 配置并打开编辑界面。</p><p>将该版本替换为刚才安装的 Fabric Loader 版本并点击 <code>保存</code>。</p><p><img src="/assets/players/updating-fabric.png" alt="在 Minecraft 启动器中更新 Fabric Loader 版本" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. 搞定！ <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. 搞定！”">​</a></h2><p>完成这些步骤后，就可以回到 <code>Play</code> 选项卡，从左下角的下拉菜单中选择 Fabric 配置文件，然后按下启动按钮！</p><p>如果在遵循本指南时遇到任何问题，可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道中寻求帮助。</p>`,25)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};